  'imiasalvio':       { name: 'Mia Salvio',         reliability: 72, tier: 2 }
};

const items = $input.all();
const tweets = [];

for (const item of items) {
  const tweet = item.json;
  const text = tweet.full_text || tweet.text || tweet.tweetText || tweet.body || '';
  const tweetId = tweet.id_str || tweet.id || tweet.tweetId || `gen_${Date.now()}_${Math.random()}`;
  const handle = (tweet.user?.screen_name || tweet.author?.userName || tweet.authorMeta?.screenName || '').toLowerCase();
  const meta = ACCOUNTS[handle] || { name: handle, reliability: 60, tier: 3 };

  if (!text || text.startsWith('RT @') || text.startsWith('@') || text.length < 30) continue;

  const normalized = text.toLowerCase().replace(/[^a-z0-9Ã ÃĐÃĻÃŠÃđÃīÃŪÃŊ]/g, '').substring(0, 120);
  const contentHash = Buffer.from(normalized).toString('base64').substring(0, 24);
  const words = text.toLowerCase().split(/\s+/).filter(w => w.length > 5);
  const semanticHash = Buffer.from(words.slice(0, 8).sort().join('')).toString('base64').substring(0, 16);

  tweets.push({ json: {
    tweet_id:           String(tweetId),
    content_hash:       contentHash,
    semantic_hash:      semanticHash,
    text:               text.substring(0, 600),
    created_at:         tweet.created_at || tweet.createdAt || new Date().toISOString(),
    author_handle:      handle,
    author_name:        meta.name,
    source_reliability: meta.reliability,
    source_tier:        meta.tier,
    likes:              tweet.favorite_count || tweet.likeCount || tweet.likes || 0,
    retweets:           tweet.retweet_count || tweet.retweetCount || tweet.retweets || 0,
    url:                tweet.url || tweet.tweetUrl || `https://twitter.com/${handle}/status/${tweetId}`
  }});
}

console.log(`Tweets rÃĐcupÃĐrÃĐs : ${tweets.length}`);
return tweets.length > 0 ? tweets : [{ json: { error: 'aucun tweet valide' } }];

