let existing = [];
try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://aiesvzdvlownkcjbkgjv.supabase.co/rest/v1/rumors?select=rumor_id,content_hash,semantic_hash,player_name,source_handles,reliability,odd_yes,odd_no&status=eq.open&limit=300',
    headers: {
