      'Authorization': 'Bearer sb_publishable_Ipu5bJO_zD1ckygwQmpcuw_Tl5xWmyK'
    }
  });
  existing = Array.isArray(response) ? response : [];
} catch(e) {
  console.log('Erreur chargement rumors:', String(e.message));
  existing = [];
}

const allItems = $input.all();
const results = [];

for (const item of allItems) {
  const tweet = item.json;
  if (!tweet || typeof tweet !== 'object') continue;

  const text = String(tweet.text || '');
  const contentHash = String(tweet.content_hash || '');
  const semanticHash = String(tweet.semantic_hash || '');
  const authorHandle = String(tweet.author_handle || '');
  const sourceReliability = Number(tweet.source_reliability || 60);

  const exactMatch = existing.find(r => r.content_hash && r.content_hash === contentHash);
  if (exactMatch) {
    results.push({ json: { action: 'SKIP', reason: 'Doublon exact', tweet_id: String(tweet.tweet_id || '') } });
    continue;
  }

  const semiMatch = existing.find(r => r.semantic_hash && r.semantic_hash === semanticHash);
  if (semiMatch) {
    results.push({ json: { action: 'SKIP', reason: 'Quasi-doublon', tweet_id: String(tweet.tweet_id || '') } });
    continue;
  }

  const properNouns = text.match(/[A-ZÃ-Ã][a-zÃ -Ãž]{4,}/g) || [];
  const sameRumor = existing.find(r => {
    if (!r.player_name) return false;
    const lastName = r.player_name.split(' ').pop().toLowerCase();
    return properNouns.some(n => n.toLowerCase() === lastName);
  });

  if (sameRumor) {
    const handles = Array.isArray(sameRumor.source_handles) ? sameRumor.source_handles : [];
    if (handles.includes(authorHandle)) {
      results.push({ json: { action: 'SKIP', reason: 'Source dÃĐjÃ  enregistrÃĐe', tweet_id: String(tweet.tweet_id || '') } });
    } else {
      results.push({ json: {
        action: 'ENRICH',
        existing_rumor_id: String(sameRumor.rumor_id || ''),
        existing_reliability: Number(sameRumor.reliability || 50),
        existing_odd_yes: Number(sameRumor.odd_yes || 2),
        existing_odd_no: Number(sameRumor.odd_no || 2),
        new_source_handle: authorHandle,
        new_source_reliability: sourceReliability,
        tweet_id: String(tweet.tweet_id || ''),
        tweet_text: text.substring(0, 300),
        tweet_author_name: String(tweet.author_name || ''),
        tweet_content_hash: contentHash,
        tweet_semantic_hash: semanticHash,
        tweet_url: String(tweet.url || ''),
        tweet_likes: Number(tweet.likes || 0),
        tweet_retweets: Number(tweet.retweets || 0),
        tweet_source_tier: Number(tweet.source_tier || 2),
        tweet_created_at: String(tweet.created_at || new Date().toISOString())
      }});
    }
    continue;
  }

  results.push({ json: {
    action: 'CREATE',
    tweet_id: String(tweet.tweet_id || ''),
    tweet_text: text.substring(0, 300),
    tweet_author_handle: authorHandle,
    tweet_author_name: String(tweet.author_name || ''),
    tweet_source_reliability: sourceReliability,
    tweet_source_tier: Number(tweet.source_tier || 2),
    tweet_content_hash: contentHash,
    tweet_semantic_hash: semanticHash,
    tweet_url: String(tweet.url || ''),
    tweet_likes: Number(tweet.likes || 0),
    tweet_retweets: Number(tweet.retweets || 0),
    tweet_created_at: String(tweet.created_at || new Date().toISOString())
  }});
}

console.log(`Anti-doublons: ${allItems.length} entrees => ${results.filter(r=>r.json.action!=='SKIP').length} a traiter`);
return results.length > 0 ? results : [{ json: { action: 'SKIP', reason: 'Aucun item', tweet_id: '' } }];

const data = $json;
const currentReliability = data.existing_reliability || 50;
const newSourceBoost = Math.round(data.new_source_reliability * 0.12);
const newReliability = Math.min(98, currentReliability + newSourceBoost + 5);
const prob = newReliability / 100;
const margin = newReliability >= 80 ? 0.04 : 0.06;
const newOddYes = Math.max(1.01, Math.min(20, parseFloat((1/(prob+margin)).toFixed(2))));
const newOddNo  = Math.max(1.01, Math.min(20, parseFloat((1/(1-prob+margin)).toFixed(2))));
return [{ json: { existing_rumor_id: data.existing_rumor_id, new_source_handle: data.new_source_handle, new_reliability: newReliability, new_odd_yes: newOddYes, new_odd_no: newOddNo } }];

